changeSet.sql:
-- Remap "OHP maszyna" -> "Machine Overhead Press" (catalog) UPDATE workout_set SET exercise_id = (SELECT id FROM exercise WHERE user_id IS NULL AND name = 'Machine Overhead Press') WHERE exercise_id IN ( SELECT id FROM exercise WHERE user_id = (SELECT id FROM app_user WHERE LOWER(nick) = 'kapiet') AND name = 'OHP maszyna' );
-- Remap "OHP hantle" -> "Dumbbell Overhead Press" (catalog) UPDATE workout_set SET exercise_id = (SELECT id FROM exercise WHERE user_id IS NULL AND name = 'Dumbbell Overhead Press') WHERE exercise_id IN ( SELECT id FROM exercise WHERE user_id = (SELECT id FROM app_user WHERE LOWER(nick) = 'kapiet') AND name = 'OHP hantle' );
-- Now safe to delete the orphan user exercises DELETE FROM exercise WHERE user_id = (SELECT id FROM app_user WHERE LOWER(nick) = 'kapiet') AND name IN ('OHP maszyna', 'OHP hantle');
